[FormDataSourceEventHandler(formDataSourceStr(LedgerJournalTransVendPaym, LedgerJournalTrans), FormDataSourceEventType::Activated)]
public static void LedgerJournalTrans_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{

    LedgerJournalTrans  ledgerJournalTrans = sender.cursor();
    LedgerJournalTable  journalTable = ledgerJournalTrans.ledgerJournalTable();
    ETG_Parameters      etgParameters = ETG_Parameters::find();

    boolean isPaymRefMandatory = false;
    boolean isDocNumMandatory = false;

    if (journalTable && journalTable.JournalType == LedgerJournalType::Payment)
    {
        isPaymRefMandatory = (etgParameters.ValidateVendorPaymentReference == NoYes::Yes);
        isDocNumMandatory = (etgParameters.ValidateVendorDocument == NoYes::Yes);
    }


    sender.object(fieldNum(LedgerJournalTrans, PaymReference)).mandatory(isPaymRefMandatory);
    sender.object(fieldNum(LedgerJournalTrans, DocumentNum)).mandatory(isDocNumMandatory);



    FormRun formRun = sender.formRun();
    FormStringControl paymentControl = formRun.control(formRun.controlId("LedgerJournalTrans_Payment")) as FormStringControl;

    if (paymentControl)
    {

        paymentControl.mandatory(true);
    }

    if (ETG_Parameters::find().ETGDocumentDate == NoYes::Yes)
    {
        sender.object(fieldNum(LedgerJournalTrans, DocumentDate)).mandatory(true);
    }
    else
    {
        sender.object(fieldNum(LedgerJournalTrans, DocumentDate)).mandatory(false);
    }


}
